// Smart Router: detect request type
const req = $input.first().json;
const body = req.body || req || {};
const headers = req.headers || {};
const query = req.query || {};

const isLineSignature = headers['x-line-signature'] !== undefined ||
  (Array.isArray(body.events) && body.events.length > 0);

const messageText = (body.message || body.text || '').toString().toLowerCase();
const statsKeywords = ['สรุปผล', 'สถิติ', 'stats', 'summary', 'รายงาน', 'list', 'ทั้งหมด', 'all'];
const isStats = !!statsKeywords.find(k => messageText.includes(k.toLowerCase())) || body.mode === 'stats';

const isRegistry = body.filename !== undefined || body.file_name !== undefined;

// Routing priority:
// 1. LINE events (highest)
// 2. Registry (filename present)
// 3. Stats (keyword or mode=stats)
// 4. Search HTML (default - including mode=vector and mode=list)
let route = 'search_html';
if (isLineSignature) route = 'line_event';
else if (isRegistry) route = 'registry_insert';
else if (isStats) route = 'stats_text';

const result = {
  _route: route,
  _body: body,
  _events: body.events || [],
  _query: query,
  _mode: body.mode || 'list',
  _q: body.q || '',
  _days: body.days || 7,
  _headers: headers
};
if (isLineSignature && body.events && body.events.length > 0) {
  result._event = body.events[0];
  result._replyToken = body.events[0].replyToken;
}
return [{ json: result }];

