// Parse Ollama response - robust text fallback using string matching
const resp = $('AI Agent (Ollama)').first().json;
const msg = resp.message || {};
let toolCalls = msg.tool_calls || [];
const content = (msg.content || '').trim();
const thinking = (msg.thinking || '').trim();
const allText = content + ' ' + thinking;

// FALLBACK: detect tool call from text using simple string matching
if (toolCalls.length === 0 && content) {
  let detectedTool = null;
  if (content.includes('list_documents') || allText.includes('list_documents')) {
    detectedTool = 'list_documents';
  } else if (content.includes('search_documents') || allText.includes('search_documents')) {
    detectedTool = 'search_documents';
  } else if (content.includes('get_stats') || allText.includes('get_stats')) {
    detectedTool = 'get_stats';
  }

  if (detectedTool) {
    // Try to extract args from "(...)" 
    let args = {};
    const parenMatch = content.match(new RegExp(detectedTool + '\\s*\\(([^)]*)\\)'));
    if (parenMatch) {
      const argsStr = parenMatch[1];
      // Match filter="..." or query="..." or limit=N
      const stringArg = argsStr.match(/(?:filter|query)\\s*=\\s*"([^"]*)"/);
      if (stringArg) {
        if (detectedTool === 'search_documents') args.query = stringArg[1];
        else args.filter = stringArg[1];
      }
      const intArg = argsStr.match(/limit\\s*=\\s*(\\d+)/);
      if (intArg) args.limit = parseInt(intArg[1]);
    }
    toolCalls = [{
      id: 'fallback-' + Date.now(),
      function: { name: detectedTool, arguments: args }
    }];
  }
}

if (toolCalls.length > 0) {
  const tc = toolCalls[0];
  const toolName = tc.function.name;
  const args = typeof tc.function.arguments === 'string'
    ? (tc.function.arguments.trim() ? JSON.parse(tc.function.arguments) : {})
    : (tc.function.arguments || {});

  if (toolName === 'search_documents') {
    return [{
      json: {
        _route: 'ai_search',
        _query: args.query || '',
        _limit: args.limit || 5,
        _tool_call_id: tc.id,
        _tool_name: toolName
      }
    }];
  } else if (toolName === 'list_documents') {
    return [{
      json: {
        _route: 'ai_list',
        _filter: args.filter || '',
        _limit: args.limit || 10,
        _tool_call_id: tc.id,
        _tool_name: toolName
      }
    }];
  } else if (toolName === 'get_stats') {
    return [{
      json: {
        _route: 'ai_stats',
        _tool_call_id: tc.id,
        _tool_name: toolName
      }
    }];
  }
}

return [{
  json: {
    _route: 'ai_text',
    _text: content || 'ขออภัย ระบบไม่สามารถประมวลผลได้ในขณะนี้'
  }
}];

// Build LINE Flex message from search results
const searchResp = $('AI: Call Vector Search').first().json;
const query = $('Parse AI Response').first().json._query;
const results = (searchResp.results || []).slice(0, 5);

if (!results.length) {
  // No results - simple text with admin UI link
  return [{
    json: {
      _flex: null,
      _fallback: `🔍 ไม่พบเอกสารที่เกี่ยวข้องกับ "${query}"\n\nเปิดดูเอกสารทั้งหมด: https://n8n.jesadakorn.com/webhook/docs-admin-ui?q=${encodeURIComponent(query)}\n\nลองค้นหาด้วยคำอื่น หรือพิมพ์ "สรุปผล" เพื่อดูภาพรวม`
    }
  }];
}

// URL-encode query for the admin UI link
const adminUrl = `https://n8n.jesadakorn.com/webhook/docs-admin-ui?q=${encodeURIComponent(query)}`;

// Build Flex card with carousel of results
const bubbles = results.map(r => {
  const sim = ((r.similarity || 0) * 100).toFixed(1);
  const contentPreview = (r.content || '').slice(0, 100).replace(/\n/g, ' ');
  const headerText = (r.doc_no && r.doc_no.length > 0) ? r.doc_no : '🔍 ' + (r.file_name || 'document').slice(0, 20);
  const docNo = (r.doc_no && r.doc_no.length > 0) ? r.doc_no : '';
  return {
    type: 'bubble',
    size: 'mega',
    header: {
      type: 'box',
      layout: 'vertical',
      contents: [
        {
          type: 'text',
          text: headerText,
          weight: 'bold',
          size: 'sm',
          color: '#1a3a5c',
          wrap: true
        }
      ],
      backgroundColor: '#f5f7fa',
      paddingAll: 'sm'
    },
    body: {
      type: 'box',
      layout: 'vertical',
      contents: [
        {
          type: 'text',
          text: r.file_name || '',
          weight: 'bold',
          size: 'md',
          wrap: true
        },
        {
          type: 'box',
          layout: 'baseline',
          margin: 'md',
          contents: [
            {
              type: 'text',
              text: `📊 ${sim}% match`,
              size: 'xs',
              color: '#0a6b3e',
              weight: 'bold'
            },
            {
              type: 'text',
              text: ` · chunk #${r.chunk_index || 0}`,
              size: 'xs',
              color: '#999999'
            }
          ]
        },
        {
          type: 'text',
          text: contentPreview + '...',
          size: 'xs',
          color: '#666666',
          wrap: true,
          margin: 'md'
        }
      ]
    },
    footer: {
      type: 'box',
      layout: 'vertical',
      contents: [
        {
          type: 'button',
          style: 'primary',
          color: '#1a3a5c',
          action: {
            type: 'uri',
            label: '📂 เปิดในระบบ',
            uri: adminUrl
          }
        },
        {
          type: 'button',
          style: 'secondary',
          margin: 'sm',
          action: {
            type: 'uri',
            label: docNo ? ('ดู ' + docNo) : '📋 ดูเอกสารทั้งหมด',
            uri: adminUrl
          }
        }
      ]
    }
  };
});

const flex = {
  type: 'flex',
  altText: `🔍 ผลการค้นหา: ${query} (${results.length} รายการ)`,
  contents: {
    type: 'carousel',
    contents: bubbles
  }
};

return [{
  json: {
    _flex: flex,
    _fallback: `🔍 ผลการค้นหา: ${query} (${results.length} รายการ)\n\nเปิดดูในระบบ: ${adminUrl}`,
    _result_count: results.length,
    _query: query
  }
}];

// Format list of contracts as readable Thai text
const allItems = $('AI: List Contracts').all().map(i => i.json);
const rows = allItems.filter(r => !r._is_dummy);
const filter = $json._filter || '';
const limit = $json._limit || 10;

if (rows.length === 0) {
  const emptyText = filter
    ? `ไม่พบเอกสารที่ตรงกับ "${filter}"\n\nลองค้นหาด้วยคำอื่น หรือพิมพ์ "สรุปผล" เพื่อดูภาพรวม`
    : 'ตอนนี้ยังไม่มีเอกสารในระบบเลยครับ\n\nส่ง PDF/รูปภาพ เข้า LINE OA เพื่อเริ่มอัปโหลดได้เลย';
  return [{ json: { _text: emptyText } }];
}

let text = filter
  ? `📋 พบ ${rows.length} เอกสารที่ตรงกับ "${filter}" (แสดง ${rows.length}/${limit}):\n\n`
  : `📋 ตอนนี้มี ${rows.length} เอกสารในระบบ (แสดง ${rows.length}/${limit}):\n\n`;

rows.forEach((r, i) => {
  const statusEmoji = r.status === 'ready' ? '✅' : r.status === 'pending' ? '⏳' : r.status === 'failed' ? '❌' : '❔';
  const date = r.uploaded_at ? new Date(r.uploaded_at).toLocaleDateString('th-TH', { year: 'numeric', month: 'short', day: 'numeric' }) : '';
  text += `${i+1}. ${statusEmoji} ${r.file_name}`;
  if (r.doc_no) text += ` (${r.doc_no})`;
  if (r.category) text += `\n   หมวด: ${r.category} | chunks: ${r.chunk_count} | ${date}`;
  text += '\n';
});

text += '\n💡 พิมพ์ "หา[คำค้น]" เพื่อค้นหาแบบ semantic | "สรุปผล" เพื่อดูภาพรวม';

return [{ json: { _text: text } }];

const rows = $('AI: Get Stats').all().map(i => i.json);
const s = rows[0] || {};

let text = `📊 สรุปภาพรวมเอกสาร\n\n`;
text += `📁 ทั้งหมด: ${s.total || 0} เอกสาร\n`;
text += `✅ พร้อมใช้งาน: ${s.ready || 0}\n`;
text += `⏳ กำลังประมวลผล: ${s.pending || 0}\n`;
text += `❌ ล้มเหลว: ${s.failed || 0}\n\n`;

if (s.by_category && Array.isArray(s.by_category)) {
  text += `📂 แยกตามหมวดหมู่:\n`;
  s.by_category.forEach(c => {
    text += `  • ${c.category}: ${c.count} ฉบับ\n`;
  });
}

text += `\n💡 พิมพ์ \"list\" เพื่อดูเอกสารทั้งหมด | \"หา[คำค้น]\" เพื่อค้นหา`;

return [{ json: { _text: text } }];

// Read q from either URL query OR body
const wrapped = $input.first().json;
const q = wrapped._query || wrapped.query || {};
const body = wrapped._body || wrapped.body || wrapped || {};
const query = (q.q || body.q || '').toString().trim();
return [{json: {query}}];

// Format vector search results as JSON
const rows = $input.all().map(i => i.json).filter(r => r && r.contract_id);
return [{json: {
  ok: true,
  query: $('JS-VS Parse').first().json.query,
  count: rows.length,
  results: rows.map(r => ({
    contract_id: r.contract_id,
    doc_no: r.doc_no,
    file_name: r.file_name,
    chunk_index: r.chunk_index,
    content: r.content,
    similarity: parseFloat(r.similarity) || 0
  }))
}}];

// Build a safe LINE message from Build Flex Card output
const bfc = $('AI: Build Flex Card').first().json;
let message = null;

// Try _flex first
if (bfc && bfc._flex) {
  // Validate Flex structure
  const flex = bfc._flex;
  if (flex.type === 'flex' && flex.altText && flex.contents) {
    message = flex;
  } else {
    // Malformed Flex - log and fall back to text
    console.log('Invalid Flex structure, falling back to text:', JSON.stringify(flex).slice(0, 200));
  }
}

// Try _fallback second
if (!message && bfc && bfc._fallback && typeof bfc._fallback === 'string' && bfc._fallback.length > 0) {
  message = { type: 'text', text: bfc._fallback };
}

// Last resort: generic text
if (!message) {
  message = { type: 'text', text: 'ไม่สามารถแสดงผลได้ในขณะนี้' };
}

return [{json: {message}}];
